function parseData(input: string): number {
  const val = parseInt(input);
  if (isNaN(val)) throw new Error("Not a number");
  return val;
}

examples.toCode:
import (
    "errors"
    "strconv"
)

func parseData(input string) (int, error) {
    val, err := strconv.Atoi(input)
    if (err != nil) {
        return 0, errors.New("not a number")
    }
    return val, nil
}
